```javascript
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');
const morgan = require('morgan');
const jwt = require('jsonwebtoken');
require('dotenv').config();

const app = express();

// ===== Security Middleware =====

// Security headers
app.use(helmet());

// CORS configuration
app.use(cors({
  origin: (process.env.ALLOWED_ORIGINS || 'http://localhost:3000').split(','),
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
}));

// Body parsing with size limits
app.use(express.json({ limit: '10kb' }));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
});
app.use(limiter);

// Logging
app.use(morgan('combined'));

// ===== Authentication Middleware =====

const authenticate = (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Unauthorized' });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded;
    next();
  } catch {
    return res.status(403).json({ error: 'Invalid token' });
  }
};

// ===== Routes =====

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', authenticate, (req, res) => {
  // Sanitized response - no sensitive data
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);
});

// ===== Error Handling =====

app.use((err, req, res, next) => {
  console.error('Error:', {
    timestamp: new Date().toISOString(),
    method: req.method,
    path: req.path,
    error: err.message,
  });

  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production' 
      ? 'Internal Server Error' 
      : err.message,
  });
});

// ===== Server Startup =====

const PORT = process.env.PORT || 3000;
const NODE_ENV = process.env.NODE_ENV || 'development';

// Validate required environment variables
['JWT_SECRET'].forEach(envVar => {
  if (!process.env[envVar] && NODE_ENV === 'production') {
    throw new Error(`Missing required environment variable: ${envVar}`);
  }
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT} in ${NODE_ENV} mode`);
});

module.exports = app;
```

---

### 🛠️ Implementation Checklist

- [ ] Install dependencies: `npm install helmet express-rate-limit cors morgan jsonwebtoken dotenv`
- [ ] Create `.env` file with required variables (never commit to git)
- [ ] Add input validation for all endpoints
- [ ] Implement authentication/authorization
- [ ] Add comprehensive error handling
